// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract GasPacked {

 uint256 constant TOPIC_ID = 123;
 uint256 counter = 1;

 mapping(uint256 => uint16[]) public smallItems;
 mapping(uint256 => uint256[]) public hugeItems;
 mapping(uint256 => bytes) public packedItems;

 // ── Write ────────────────────────────────────────────────────────

 function empty() public {
 counter++;
 }

 function pushSmall (uint16 _val) public {
 smallItems[TOPIC_ID].push(_val);
 empty();
 }
 function pushHuge (uint256 _val) public {
 hugeItems [TOPIC_ID].push(_val);
 empty();
 }
 function pushPacked(uint16 _val) public {
 LibPackedStorageAligned.push(packedItems[TOPIC_ID], _val, 2);
 empty();
 }

 // ── Gas benchmark ────────────────────────────────────────────────

 function benchSmall(uint256 _count) public returns (uint256 sum) {
 uint16[] storage arr = smallItems[TOPIC_ID];
 for (uint256 i; i < _count; i++) sum += arr[i];
 empty();
 }

 function benchHuge(uint256 _count) public returns (uint256 sum) {
 uint256[] storage arr = hugeItems[TOPIC_ID];
 for (uint256 i; i < _count; i++) sum += arr[i];
 empty();
 }

 function benchPacked(uint256 _count) public returns (uint256 sum) {
 (uint256[] memory items, ) = LibPackedStorageAligned.readPage(packedItems[TOPIC_ID], 0, _count, 2);
 for (uint256 i; i < _count; i++) sum += items[i];
 empty();
 }

 // read raw slot from 'smallItems'

 function readRawSmallSlot(uint256 _slotIndex) public view returns (uint256 _slotData) {
 bytes32 arraySlot;
 assembly {
 mstore(0x00, TOPIC_ID)
 mstore(0x20, smallItems.slot)
 arraySlot := keccak256(0x00, 0x40)
 }
 bytes32 firstDataSlot = keccak256(abi.encode(arraySlot));
 assembly {
 _slotData := sload(add(firstDataSlot, _slotIndex))
 }
 }
}

library LibPackedStorageAligned {
 /// @dev EVM word size in bytes (storage slot, uint256, keccak256 input, memory stride).
 uint256 internal constant WORD_BYTES = 32;
 /// @dev Bits per word (WORD_BYTES * 8). Used for full-word mask detection.
 uint256 internal constant BITS_PER_WORD = 256;

 error InvalidItemSize(uint256 itemSize);

 /// @notice Push a new item to the packed storage
 /// @param data The bytes storage array to append to
 /// @param item The item value to store (will be masked to itemSize bytes)
 /// @param itemSize Size of each item in bytes (1-32)
 function push(bytes storage data, uint256 item, uint256 itemSize) internal {
 if (itemSize == 0 || itemSize > WORD_BYTES) revert InvalidItemSize(itemSize);
 assembly ("memory-safe") {
 // Load base slot
 let slot := data.slot

 // Load current length (in bytes)
 let len := sload(slot)

 // New length (len + itemSize bytes)
 let newLen := add(len, itemSize)
 sstore(slot, newLen)

 // Storage slot where byte array contents start: keccak256(slot)
 mstore(0x00, slot)
 let dataSlot := keccak256(0x00, WORD_BYTES)

 // We must write at offset = len
 let slotDiv := div(len, WORD_BYTES)
 let writeSlot := add(dataSlot, slotDiv)
 let offset := mod(len, WORD_BYTES)

 let word := sload(writeSlot)

 // Shift: item occupies itemSize bytes at offset within WORD_BYTES-byte word
 let shift := shl(3, sub(sub(WORD_BYTES, offset), itemSize))

 // Mask from itemSize: (1 << (itemSize * 8)) - 1
 let maskBits := shl(3, itemSize)
 let itemMask
 if eq(maskBits, BITS_PER_WORD) {
 itemMask := not(0)
 }
 if iszero(eq(maskBits, BITS_PER_WORD)) {
 itemMask := sub(shl(maskBits, 1), 1)
 }

 // Insert by clearing itemSize bytes then ORing new value
 // CRITICAL: Mask the item first to ensure only itemSize bytes are used
 // Otherwise, extra bits in 'item' will corrupt the storage
 let maskedItem := and(item, itemMask)
 // Create mask: clear itemSize bytes at position 'shift'
 let shiftedMask := shl(shift, itemMask)
 let clearMask := not(shiftedMask)
 word := and(word, clearMask)
 word := or(word, shl(shift, maskedItem))

 sstore(writeSlot, word)
 }
 }

 /// @notice Get the number of items stored
 /// @param data The bytes storage array
 /// @param itemSize Size of each item in bytes (1-32)
 /// @return count The number of items stored
 function length(bytes storage data, uint256 itemSize) internal view returns (uint256 count) {
 if (itemSize == 0 || itemSize > WORD_BYTES) revert InvalidItemSize(itemSize);
 assembly ("memory-safe") {
 let slot := data.slot
 let totalBytes := sload(slot)
 count := div(totalBytes, itemSize)
 }
 }

 /// @notice Read a page of items from the packed storage
 /// @param data The bytes storage array
 /// @param pageNumber Zero-based page number
 /// @param pageSize Number of items per page
 /// @param itemSize Size of each item in bytes (1-32)
 /// @return items Array of items (as uint256, caller should cast as needed)
 function readPage(bytes storage data, uint256 pageNumber, uint256 pageSize, uint256 itemSize) internal view returns (uint256[] memory items, uint256 totalCount) {
 if (itemSize == 0 || itemSize > WORD_BYTES) revert InvalidItemSize(itemSize);
 totalCount = length(data, itemSize);
 // Special case: if pageSize is 0, return all items
 if (pageSize == 0) {
 pageNumber = 0;
 pageSize = totalCount;
 }
 uint256 start = pageNumber * pageSize;
 if (totalCount == 0 || start >= totalCount) {
 return (new uint256[](0), totalCount);
 }
 uint256 count = pageSize;
 if (count > totalCount - start) {
 count = totalCount - start;
 }
 items = _readItems(data, start * itemSize, count, itemSize);
 return (items, totalCount);
 }

 /// @notice Read a number of items from the packed storage starting at a given skipItemsCount
 /// @param data The bytes storage array
 /// @param skipItemsCount Zero-based item index to start reading from (0 = first item)
 /// @param count Maximum number of items to read and return
 /// @param itemSize Size of each item in bytes (1-32)
 /// @return items Array of items (as uint256, caller should cast as needed).
 /// Returns fewer items if skipItemsCount + count exceeds total length.
 function readFromOffset(bytes storage data, uint256 skipItemsCount, uint256 count, uint256 itemSize) internal view returns (uint256[] memory items, uint256 totalCount) {
 if (itemSize == 0 || itemSize > WORD_BYTES) revert InvalidItemSize(itemSize);
 totalCount = length(data, itemSize);
 if (skipItemsCount >= totalCount) {
 return (new uint256[](0), totalCount);
 }
 uint256 itemsToRead = count;
 if (itemsToRead > totalCount - skipItemsCount) {
 itemsToRead = totalCount - skipItemsCount;
 }
 items = _readItems(data, skipItemsCount * itemSize, itemsToRead, itemSize);
 return (items, totalCount);
 }

 /// @dev Internal helper: reads `count` items starting at `byteOffset` (in bytes).
 /// Caps count to available items if byteOffset + count would exceed storage.
 function _readItems(bytes storage data, uint256 byteOffset, uint256 count, uint256 itemSize) private view returns (uint256[] memory items) {
 assembly ("memory-safe") {
 let baseSlot := data.slot
 let totalBytes := sload(baseSlot)

 // Cap count to available items from byteOffset
 let availableBytes := sub(totalBytes, byteOffset)
 let availableItems := div(availableBytes, itemSize)
 if gt(count, availableItems) {
 count := availableItems
 }

 if iszero(count) {
 items := mload(0x40)
 mstore(items, 0)
 mstore(0x40, add(items, WORD_BYTES))
 }

 if gt(count, 0) {
 items := mload(0x40)
 mstore(items, count)
 let outPtr := add(items, WORD_BYTES)

 mstore(0x00, baseSlot)
 let dataSlot := keccak256(0x00, WORD_BYTES)

 let slotOffset := add(dataSlot, div(byteOffset, WORD_BYTES))
 let pos := mod(byteOffset, WORD_BYTES)

 let maskBits := shl(3, itemSize)
 let itemMask
 if eq(maskBits, BITS_PER_WORD) {
 itemMask := not(0)
 }
 if iszero(eq(maskBits, BITS_PER_WORD)) {
 itemMask := sub(shl(maskBits, 1), 1)
 }

 let word := sload(slotOffset)
 for { let i := 0 } lt(i, count) { i := add(i, 1) } {
 if iszero(lt(pos, WORD_BYTES)) {
 slotOffset := add(slotOffset, 1)
 word := sload(slotOffset)
 pos := sub(pos, WORD_BYTES)
 }
 let shift := shl(3, sub(sub(WORD_BYTES, pos), itemSize))
 let extracted := and(shr(shift, word), itemMask)
 mstore(outPtr, extracted)
 outPtr := add(outPtr, WORD_BYTES)
 pos := add(pos, itemSize)
 }

 mstore(0x40, outPtr)
 }
 }
 }
}
