Ж. Дополнительно: Длина строк
Это не оптимизация, но особенность работы с UTF-8 строками, которая для меня оказалась неожиданна: каждый символ может занимать от 1 до 4 байт, при этом в первых битах хранится его длина. При этом в строке могут быть символы разной размерности. Поэтому чтобы посчитать длину строки, недостаточно сконвертировать ее в bytes и затем взять length, надо пройти по каждому символу и узнать его размер.
В примере ниже мы берем первый (очередной) байт
let c := byte(0, calldataload(i))
, и затем смотрим, что в первых битах (это три шага
shr
). Если находим 0, 6, Е, 1Е, то это соответственно длина 1, 2, 3, 4, иначе - косяк. Двигаем i по строке на нужное количество байт и берем очередной байт и смотрим в нем очередную длину символа.
function getLengthFromCalldata(string calldata _input) internal pure returns (uint256 _len) {
 assembly {
 let i := _input.offset
 let end := add(i, _input.length)

 for {} lt(i, end) {} {
 let c := byte(0, calldataload(i))

 switch shr(7, c)
 case 0 { i := add(i, 1) }
 default {
 switch shr(5, c)
 case 0x6 { i := add(i, 2) }
 default {
 switch shr(4, c)
 case 0xE { i := add(i, 3) }
 default {
 switch shr(3, c)
 case 0x1E { i := add(i, 4) }
 default { revert(0, 0) }
 }
 }
 }
 _len := add(_len, 1)
 }
 }
 }
